/* ============================================================
   CRONOGRAMA (imprimible)
   ============================================================ */
function Cronograma({ ev, onBack }) {
  const bloques = [];
  if (ev.horaArmado) bloques.push({ hora: ev.horaArmado, detalle: "Armado" });
  (ev.cronograma || []).forEach(c => bloques.push(c));
  if (ev.horaDesarme) {
    bloques.push({ hora: ev.horaFin, detalle: "Fin del evento" });
    bloques.push({ hora: ev.horaDesarme, detalle: "Desarme" });
  }
  const ordenados = bloques.slice().sort((a, b) => (a.hora || "").localeCompare(b.hora || ""));

  return (
    <div>
      <div className="no-print flex gap-2 mb-4">
        <button onClick={() => window.print()} className="px-4 py-2 rounded text-sm font-medium" style={{ background: INK_SOFT, color: PAPER, fontFamily: FONT_BODY }}>Imprimir cronograma</button>
        <button onClick={onBack} className="px-4 py-2 rounded text-sm font-medium" style={{ border: `1px solid ${LINE}`, color: INK, fontFamily: FONT_BODY }}>Volver</button>
      </div>
      <div className="p-6" style={{ background: CARD, border: `1px solid ${INK}`, maxWidth: 640, margin: "0 auto" }}>
        <PrintHeader eyebrow="Cronograma / hoja de ruta" titulo={ev.salon || "Salón"} />
        <p style={{ fontFamily: FONT_BODY, fontSize: 13, color: MUTED, marginBottom: 16 }}>{fmtFecha(ev.fecha)}</p>

        <div className="flex flex-col gap-2 mb-5">
          {ordenados.map((b, i) => (
            <div key={i} className="flex items-center gap-3 p-2.5 rounded" style={{ background: HILITE_BG }}>
              <span style={{ fontFamily: FONT_MONO, fontSize: 13, color: INK, minWidth: 60 }}>{b.hora || "--:--"}</span>
              <span style={{ fontFamily: FONT_BODY, fontSize: 13, fontWeight: 600, color: INK }}>{b.detalle}</span>
            </div>
          ))}
          {!ordenados.length && <p style={{ fontFamily: FONT_BODY, fontSize: 13, color: MUTED }}>Sin ítems de cronograma cargados todavía.</p>}
        </div>

        {ev.incluye?.length > 0 && (
          <>
            <p style={{ fontFamily: FONT_BODY, fontSize: 12, textTransform: "uppercase", letterSpacing: "0.06em", color: MUTED, marginBottom: 8 }}>Tareas de armado</p>
            <div className="flex flex-col gap-1.5 mb-4">
              {ev.incluye.map((item, i) => (
                <label key={i} className="flex items-center gap-2" style={{ fontFamily: FONT_BODY, fontSize: 13.5, color: INK }}>
                  <input type="checkbox" /> {item}
                </label>
              ))}
            </div>
          </>
        )}

        <p style={{ fontFamily: FONT_BODY, fontSize: 13.5, color: INK }}>
          <b>Personas:</b> {ev.personas || "-"} {ev.servicio ? `· Servicio: ${ev.servicio}` : ""}
        </p>
        {ev.notas && <p style={{ fontFamily: FONT_BODY, fontSize: 13.5, color: INK, marginTop: 6 }}><b>Notas:</b> {ev.notas}</p>}
      </div>
    </div>
  );
}

/* ============================================================
   ESTADÍSTICAS
   ============================================================ */
function Stats({ events }) {
  const [year, setYear] = useState(new Date().getFullYear());
  const [month, setMonth] = useState(new Date().getMonth());

  const delMes = useMemo(() => events.filter(e => {
    const d = fromISO(e.fecha);
    return d.getFullYear() === year && d.getMonth() === month;
  }), [events, year, month]);

  const totalEventos = delMes.length;
  const totalHoras = delMes.reduce((acc, e) => acc + horasEntre(e.horaInicio, e.horaFin), 0);
  const totalCubiertos = delMes.reduce((acc, e) => acc + (Number(e.comanda?.cubiertos) || 0), 0);

  const porSalon = useMemo(() => {
    const map = {};
    delMes.forEach(e => {
      const s = e.salon || "Sin salón";
      map[s] = map[s] || { eventos: 0, horas: 0, cubiertos: 0 };
      map[s].eventos += 1;
      map[s].horas += horasEntre(e.horaInicio, e.horaFin);
      map[s].cubiertos += Number(e.comanda?.cubiertos) || 0;
    });
    return Object.entries(map).sort((a, b) => b[1].eventos - a[1].eventos);
  }, [delMes]);

  const maxEventos = Math.max(1, ...porSalon.map(([, v]) => v.eventos));

  return (
    <div className="flex flex-col gap-4">
      <div className="no-print flex gap-2 items-center">
        <select style={{ ...inputStyle, width: "auto" }} value={month} onChange={e => setMonth(Number(e.target.value))}>
          {MESES.map((m, i) => <option key={m} value={i}>{m}</option>)}
        </select>
        <input type="number" style={{ ...inputStyle, width: 100 }} value={year} onChange={e => setYear(Number(e.target.value))} />
        <button onClick={() => window.print()} className="px-4 py-2 rounded text-sm font-medium ml-auto" style={{ background: INK_SOFT, color: PAPER, fontFamily: FONT_BODY }}>Imprimir</button>
      </div>

      <div className="p-6 rounded" style={{ background: CARD, border: `1px solid ${INK}` }}>
        <PrintHeader eyebrow="Estadística mensual" titulo={`${MESES[month]} ${year}`} />

        <div className="grid grid-cols-3 gap-4 mb-6">
          <div className="p-4 rounded text-center" style={{ background: HILITE_BG }}>
            <p style={{ fontFamily: FONT_HEAD, fontSize: 30, color: INK }}>{totalEventos}</p>
            <p style={{ fontFamily: FONT_BODY, fontSize: 11.5, color: MUTED, textTransform: "uppercase", letterSpacing: "0.06em" }}>Eventos</p>
          </div>
          <div className="p-4 rounded text-center" style={{ background: HILITE_BG }}>
            <p style={{ fontFamily: FONT_HEAD, fontSize: 30, color: INK }}>{totalHoras.toFixed(1)}</p>
            <p style={{ fontFamily: FONT_BODY, fontSize: 11.5, color: MUTED, textTransform: "uppercase", letterSpacing: "0.06em" }}>Horas totales</p>
          </div>
          <div className="p-4 rounded text-center" style={{ background: HILITE_BG }}>
            <p style={{ fontFamily: FONT_HEAD, fontSize: 30, color: INK }}>{totalCubiertos}</p>
            <p style={{ fontFamily: FONT_BODY, fontSize: 11.5, color: MUTED, textTransform: "uppercase", letterSpacing: "0.06em" }}>Cubiertos vendidos</p>
          </div>
        </div>

        <p style={{ fontFamily: FONT_BODY, fontSize: 12, textTransform: "uppercase", letterSpacing: "0.06em", color: MUTED, marginBottom: 10 }}>Por salón</p>
        <div className="flex flex-col gap-2">
          {porSalon.map(([salon, v]) => (
            <div key={salon}>
              <div className="flex justify-between mb-1" style={{ fontFamily: FONT_BODY, fontSize: 13, color: INK }}>
                <span>{salon}</span>
                <span style={{ color: MUTED }}>{v.eventos} eventos · {v.horas.toFixed(1)} hs · {v.cubiertos} cubiertos</span>
              </div>
              <div style={{ height: 8, borderRadius: 4, background: LINE }}>
                <div style={{ height: 8, borderRadius: 4, width: `${(v.eventos / maxEventos) * 100}%`, background: ACCENT }} />
              </div>
            </div>
          ))}
          {!porSalon.length && <p style={{ fontFamily: FONT_BODY, fontSize: 13, color: MUTED }}>Sin eventos cargados este mes.</p>}
        </div>
      </div>
    </div>
  );
}

